toolCalls.args:
{"command": "# Use readelf with size info to find exact function ranges
SYMDIR="/tmp/sv-4ced125dadce48c9b9b51d00c4e5f824/symbols"
LIB="$SYMDIR/libmonosgen-2.0.so"

# Get function symbols with sizes
readelf --dyn-syms "$LIB" 2>/dev/null | awk '$4 == "FUNC" && $2 != "0000000000000000" {print $2, $3, $NF}' | sort > /tmp/sv-4ced125dadce48c9b9b51d00c4e5f824/syms_sized.txt

echo "=== Resolving all addresses using function ranges ==="
for pc in 0x222098 0x2241ac 0x1abc80 0x16de04 0x2f4b20 0x2f4c84 0x2c1a40; do
  result=$(awk -v target="$pc" '
    BEGIN { t = strtonum(target) }
    {
      addr = strtonum("0x"$1)
      size = strtonum($2)
      if (addr <= t && t < addr + size) {
        printf "%s+0x%x (base=0x%s, size=%d)\n", $3, t - addr, $1, size
        found = 1
        exit
      }
    }
    END { if (!found) print "?? (not in any exported function range)" }
  ' /tmp/sv-4ced125dadce48c9b9b51d00c4e5f824/syms_sized.txt)
  echo "$pc -> $result"
done", "description": "Resolve addresses using function ranges", "initial_wait": 10}

arguments.command:
# Check which sections the addresses fall into
DBGFILE="/tmp/sv-4ced125dadce48c9b9b51d00c4e5f824/symbols/debug/libmonosgen-2.0.so.dbg"

echo "=== Section headers ==="
readelf -S "$DBGFILE" 2>/dev/null | grep -E "^\s+\[" | awk '{print $1, $2, $3, $4, $5, $6, $7}'

echo ""
echo "=== Checking which section 0x2f4b20 falls into ==="
readelf -S "$DBGFILE" 2>/dev/null | awk '
  /\[/ && /PROGBITS|NOBITS/ {
    gsub(/[\[\]]/, "")
    name = $2
    addr = strtonum("0x"$4)
    size = strtonum("0x"$6)
    if (addr <= 0x2f4b20 && 0x2f4b20 < addr + size) {
      printf "0x2f4b20 is in section %s (addr=0x%x, size=0x%x)\n", name, addr, size
    }
    if (addr <= 0x2f4c84 && 0x2f4c84 < addr + size) {
      printf "0x2f4c84 is in section %s (addr=0x%x, size=0x%x)\n", name, addr, size
    }
  }
'

